/**
 * Tests for Atomic Write Utility
 *
 * Uses REAL filesystem operations (no mocks) for integration-style testing.
 * Each test gets a fresh temp directory that is cleaned up after.
 *
 * Validates:
 * - atomicWriteSync writes data correctly
 * - atomicWriteSync does not corrupt original on write failure
 * - atomicWriteSync cleans up .tmp on failure
 * - acquireLock / releaseLock cycle works
 * - acquireLock times out when lock is held
 * - lockedAtomicWriteSync convenience wrapper
 * - directory auto-creation for missing parent dirs
 * - concurrent write protection via locking
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import * as fs from 'node:fs';
import * as path from 'node:path';
import * as os from 'node:os';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// Mock common.js to avoid log directory side effects
vi.mock('../../lib/common.js', () => mockCommonBasic());

import {
  atomicWriteSync,
  acquireLock,
  releaseLock,
  lockedAtomicWriteSync,
} from '../../lib/atomic-write.js';

let tmpDir: string;

beforeEach(() => {
  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ork-atomic-test-'));
});

afterEach(() => {
  // Clean up temp directory
  try {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  } catch {
    // Ignore cleanup errors
  }
});

describe('atomicWriteSync', () => {
  it('writes data correctly', () => {
    const filePath = path.join(tmpDir, 'test.txt');
    atomicWriteSync(filePath, 'hello world');

    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe('hello world');
  });

  it('writes with specified encoding', () => {
    const filePath = path.join(tmpDir, 'encoded.txt');
    atomicWriteSync(filePath, 'utf8 content', 'utf8');

    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe('utf8 content');
  });

  it('overwrites existing file atomically', () => {
    const filePath = path.join(tmpDir, 'overwrite.txt');
    fs.writeFileSync(filePath, 'original');

    atomicWriteSync(filePath, 'updated');

    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe('updated');
  });

  it('does not leave .tmp file on success', () => {
    const filePath = path.join(tmpDir, 'clean.txt');
    atomicWriteSync(filePath, 'data');

    const files = fs.readdirSync(tmpDir);
    expect(files).toEqual(['clean.txt']);
  });

  it('does not corrupt original on write failure', () => {
    const filePath = path.join(tmpDir, 'safe.txt');
    fs.writeFileSync(filePath, 'original content');

    // Create a directory at the tmp path to force writeFileSync to fail
    // (can't write to a path that's a directory)
    const tmpPath = `${filePath}.tmp.${process.pid}`;
    fs.mkdirSync(tmpPath);

    expect(() => atomicWriteSync(filePath, 'bad data')).toThrow();

    // Original file should be untouched
    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe('original content');
  });

  it('cleans up .tmp file on rename failure', () => {
    const filePath = path.join(tmpDir, 'no-rename', 'subdir', 'deep', 'file.txt');
    // Ensure the parent exists so writeFileSync works
    const dir = path.dirname(filePath);
    fs.mkdirSync(dir, { recursive: true });

    // Write a successful file first
    atomicWriteSync(filePath, 'success');
    expect(fs.readFileSync(filePath, 'utf8')).toBe('success');

    // Verify no leftover .tmp files
    const parentFiles = fs.readdirSync(dir);
    const tmpFiles = parentFiles.filter(f => f.includes('.tmp.'));
    expect(tmpFiles).toHaveLength(0);
  });

  it('creates parent directories when they do not exist', () => {
    const filePath = path.join(tmpDir, 'nested', 'deep', 'dir', 'file.txt');

    atomicWriteSync(filePath, 'nested content');

    expect(fs.existsSync(filePath)).toBe(true);
    expect(fs.readFileSync(filePath, 'utf8')).toBe('nested content');
  });

  it('handles empty string data', () => {
    const filePath = path.join(tmpDir, 'empty.txt');
    atomicWriteSync(filePath, '');

    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe('');
  });

  it('handles large data', () => {
    const filePath = path.join(tmpDir, 'large.txt');
    const largeData = 'x'.repeat(1024 * 1024); // 1MB

    atomicWriteSync(filePath, largeData);

    const content = fs.readFileSync(filePath, 'utf8');
    expect(content.length).toBe(1024 * 1024);
  });

  it('handles data with special characters', () => {
    const filePath = path.join(tmpDir, 'special.txt');
    const specialData = 'line1\nline2\ttab\r\nwindows\0null';

    atomicWriteSync(filePath, specialData);

    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe(specialData);
  });
});

describe('acquireLock / releaseLock', () => {
  it('acquires and releases a lock successfully', () => {
    const lockPath = path.join(tmpDir, 'test.lock');

    const acquired = acquireLock(lockPath, 1000);
    expect(acquired).toBe(true);
    expect(fs.existsSync(lockPath)).toBe(true);

    releaseLock(lockPath);
    expect(fs.existsSync(lockPath)).toBe(false);
  });

  it('lock directory is created as a directory', () => {
    const lockPath = path.join(tmpDir, 'dir.lock');

    acquireLock(lockPath, 1000);
    const stat = fs.statSync(lockPath);
    expect(stat.isDirectory()).toBe(true);

    releaseLock(lockPath);
  });

  it('times out when lock is already held', () => {
    const lockPath = path.join(tmpDir, 'held.lock');

    // Manually create the lock directory (simulating another process holding it)
    fs.mkdirSync(lockPath);

    // acquireLock should spin for timeoutMs, then break the stale lock
    // With a very short timeout, it should still succeed after breaking
    const acquired = acquireLock(lockPath, 100);

    // After timeout, it breaks the stale lock and re-acquires
    expect(acquired).toBe(true);

    releaseLock(lockPath);
  });

  it('releaseLock is safe to call when lock does not exist', () => {
    const lockPath = path.join(tmpDir, 'nonexistent.lock');

    // Should not throw
    expect(() => releaseLock(lockPath)).not.toThrow();
  });

  it('releaseLock is idempotent', () => {
    const lockPath = path.join(tmpDir, 'idempotent.lock');

    acquireLock(lockPath, 1000);
    releaseLock(lockPath);
    releaseLock(lockPath); // Second call should be safe

    expect(fs.existsSync(lockPath)).toBe(false);
  });

  it('cannot double-acquire without release', () => {
    const lockPath = path.join(tmpDir, 'double.lock');

    const first = acquireLock(lockPath, 1000);
    expect(first).toBe(true);

    // Second acquire from same process will spin until timeout,
    // then break the stale lock (since it's the same process)
    const second = acquireLock(lockPath, 100);
    expect(second).toBe(true); // Succeeds after breaking "stale" lock

    releaseLock(lockPath);
  });

  it('propagates unexpected errors from mkdirSync', () => {
    // Use a path under a non-existent parent without recursive flag
    // mkdirSync (non-recursive) will throw ENOENT, not EEXIST
    const lockPath = path.join(tmpDir, 'no-parent', 'deep', 'lock.dir');

    // acquireLock uses mkdirSync without recursive: true, so if the
    // parent doesn't exist, it gets ENOENT which should be thrown
    expect(() => acquireLock(lockPath, 100)).toThrow();
  });
});

describe('lockedAtomicWriteSync', () => {
  it('writes data correctly with automatic locking', () => {
    const filePath = path.join(tmpDir, 'locked.txt');

    const result = lockedAtomicWriteSync(filePath, 'locked content');

    expect(result).toBe(true);
    expect(fs.readFileSync(filePath, 'utf8')).toBe('locked content');
  });

  it('releases lock after successful write', () => {
    const filePath = path.join(tmpDir, 'release.txt');
    const lockPath = `${filePath}.lock`;

    lockedAtomicWriteSync(filePath, 'data');

    // Lock should be released
    expect(fs.existsSync(lockPath)).toBe(false);
  });

  it('releases lock even if write fails', () => {
    const filePath = path.join(tmpDir, 'fail-write.txt');
    const lockPath = `${filePath}.lock`;

    // Create a directory at the tmp file path to force writeFileSync to fail
    const tmpFilePath = `${filePath}.tmp.${process.pid}`;
    fs.mkdirSync(path.dirname(tmpFilePath), { recursive: true });
    fs.mkdirSync(tmpFilePath);

    // The write will fail, but lock should still be released
    expect(() => lockedAtomicWriteSync(filePath, 'data')).toThrow();
    expect(fs.existsSync(lockPath)).toBe(false);
  });

  it('uses custom lock path when provided', () => {
    const filePath = path.join(tmpDir, 'custom-lock.txt');
    const customLockPath = path.join(tmpDir, 'my-custom.lock');

    lockedAtomicWriteSync(filePath, 'data', customLockPath);

    // Custom lock should be released
    expect(fs.existsSync(customLockPath)).toBe(false);
    // Default lock should not have been created
    expect(fs.existsSync(`${filePath}.lock`)).toBe(false);
    // File should exist
    expect(fs.readFileSync(filePath, 'utf8')).toBe('data');
  });

  it('uses default lock path (filePath.lock) when not specified', () => {
    const filePath = path.join(tmpDir, 'default-lock.txt');

    lockedAtomicWriteSync(filePath, 'data');

    // Both file and lock cleanup should have happened
    expect(fs.readFileSync(filePath, 'utf8')).toBe('data');
    expect(fs.existsSync(`${filePath}.lock`)).toBe(false);
  });

  it('supports encoding parameter', () => {
    const filePath = path.join(tmpDir, 'encoded-locked.txt');

    lockedAtomicWriteSync(filePath, 'encoded data', undefined, 'utf8');

    expect(fs.readFileSync(filePath, 'utf8')).toBe('encoded data');
  });

  it('sequential writes produce correct final content', () => {
    const filePath = path.join(tmpDir, 'sequential.txt');

    lockedAtomicWriteSync(filePath, 'first');
    lockedAtomicWriteSync(filePath, 'second');
    lockedAtomicWriteSync(filePath, 'third');

    expect(fs.readFileSync(filePath, 'utf8')).toBe('third');
  });
});

describe('concurrent write protection', () => {
  it('multiple sequential locked writes do not corrupt data', () => {
    const filePath = path.join(tmpDir, 'concurrent.txt');
    const iterations = 20;

    for (let i = 0; i < iterations; i++) {
      const result = lockedAtomicWriteSync(filePath, `iteration-${i}`);
      expect(result).toBe(true);
    }

    // Final content should be the last iteration
    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe(`iteration-${iterations - 1}`);
  });

  it('lock prevents partial writes from being visible', () => {
    const filePath = path.join(tmpDir, 'partial.txt');

    // Write initial content
    lockedAtomicWriteSync(filePath, 'complete-data');

    // Verify the content is always a complete write, never partial
    const content = fs.readFileSync(filePath, 'utf8');
    expect(content).toBe('complete-data');
    expect(content).not.toContain('.tmp');
  });

  it('no .tmp or .lock files remain after operations', () => {
    const filePath = path.join(tmpDir, 'cleanup-check.txt');

    lockedAtomicWriteSync(filePath, 'content-1');
    lockedAtomicWriteSync(filePath, 'content-2');

    const files = fs.readdirSync(tmpDir);
    const artifacts = files.filter(f => f.includes('.tmp') || f.includes('.lock'));
    expect(artifacts).toHaveLength(0);
  });
});

